app.post('/token/revoke', (req, res) => {
  const { token, client_id, client_secret } = req.body;

  if (!client_id || !client_secret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication required.'
    });
  }

  const client = registeredClients.get(client_id);
  if (!client || !timingSafeStringCompare(client.clientSecret, client_secret)) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed.'
    });
  }

  if (token) {
    // Try to revoke as access token
    const accessData = accessTokens.get(token);
    if (accessData && accessData.clientId === client_id) {
      accessTokens.delete(token);
    }

    // Try to revoke as refresh token
    const refreshData = refreshTokens.get(token);
    if (refreshData && refreshData.clientId === client_id) {
      refreshTokens.delete(token);
    }
  }

  // Always return 200 per RFC 7009
  return res.status(200).json({});
});

